const raw = $input.first().json;
const body = raw.body || raw;
const isScheduled = !body.query && !body.command;
const query = String(body.query || body.command || '');

const today = new Date();
const day = today.getDay();
const dailyTargets = {
  1: { mode: 'grant', query: 'Maryland EARN workforce development grant 2026 drone technology training nonprofit', grantName: 'EARN_Maryland_2026.txt' },
  2: { mode: 'grant', query: 'Maryland CDBG Community Development Block Grant Baltimore City 2026 minority nonprofit facility', grantName: 'CDBG_Baltimore_2026.txt' },
  3: { mode: 'bd', query: 'BGE Baltimore Gas Electric vendor portal drone inspection NERC FAC-001 transmission line 2026' },
  4: { mode: 'grant', query: 'FEMA C-UAS SLTT Homeland Security Grant Program 2026 drone counter UAS municipal Maryland', grantName: 'FEMA_CUAS_SLTT_2026.txt' },
  5: { mode: 'bd', query: 'Maryland State Highway Administration MDSHA bridge inspection vendor registration drone Part 107 2026' }
};

let mode, resolvedQuery, grantName;
if (isScheduled) {
  const target = dailyTargets[day] || dailyTargets[1];
  mode = target.mode;
  resolvedQuery = target.query;
  grantName = target.grantName || null;
} else {
  mode = body.mode || 'bd';
  resolvedQuery = query || 'Maryland drone infrastructure inspection contracts 2026';
  grantName = body.grantName || null;
}

return [{ json: { mode, query: resolvedQuery, grantName, isScheduled, timestamp: new Date().toISOString() } }];

const fs = require('fs'), https = require('https');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }

const { mode, query, grantName, isScheduled, timestamp } = $input.first().json;
const founder = ctx.founder || {};
const verticals = ctx.verticals || {};
const entities = ctx.entities || {};
const naics = ctx.naics || {};
const dates = ctx.key_dates || {};
const revenue = ctx.revenue_targets || {};

const verticalList = Object.entries(verticals).map(([k,v]) => `${k}: ${v.name} | Pricing: ${v.pricing || v.revenue_projection || 'TBD'} | Margin: ${v.margin || 'TBD'}`).join('\n');
const eafProfile = `EAF: ${entities.EAF?.name} | EIN: ${entities.EAF?.ein} | Type: ${entities.EAF?.type} | Status: ${entities.EAF?.status}`;
const fpProfile = `FP: ${entities.FP?.name} | EIN: ${entities.FP?.ein}`;

let systemMessage, userMessage, outputFolder, outputPrefix;

if (mode === 'grant') {
  systemMessage = `You are Scout, Grant Intelligence Agent for KAI-Netics EAF.\n${eafProfile}\n${fpProfile}\nFounder: ${founder.name} — ${(founder.credentials||[]).join(', ')}\nPrograms: CAKO (12-16 week drone operator certification, zero tuition), MONK (autonomous UAS trust infrastructure)\nService area: Maryland, DC Metro, Northern Virginia\nRevenue: Y1 ${revenue.year1_total} Y2 ${revenue.year2_total}\nKey dates: MEIA ${dates.meia_capstone} | CAKO Cohort 1 ${dates.cako_cohort1_launch}\nNAICS: ${(naics.registered||[]).map(n=>n.code+' '+n.description).join(', ')}\n\nYour job: Research this grant opportunity and produce a structured grant intelligence file that Jordan can use to draft a Letter of Intent and full application. Be specific — real funder names, real portal URLs, real deadlines, real award amounts. If you cannot confirm a specific detail, say so explicitly rather than guessing.\n\nFormat your output EXACTLY as follows:\nFUNDER: [exact organization name]\nPROGRAM: [exact grant program name]\nDEADLINE: [date or rolling]\nAWARD RANGE: [dollar range]\nPORTAL: [exact URL]\nELIGIBILITY: [requirements]\nEAF FIT SCORE: [0-100%]\nFIT RATIONALE: [2-3 sentences]\nTOP 3 ALIGNMENT POINTS:\n1. [point]\n2. [point]\n3. [point]\nTOP 2 RISKS:\n1. [risk]\n2. [risk]\nRECOMMENDED ACTION: [APPLY / WATCH / PASS]\nNEXT STEP: [single most important action with URL or contact]\nLOI DRAFT:\n[250-350 word Letter of Intent draft ready for Jordan to refine]`;

  userMessage = `Research this grant opportunity for KAI-Netics EAF:\n\n${query}\n\nProduce the structured grant intelligence file. Today is ${new Date().toLocaleDateString('en-US', {timeZone: 'America/New_York'})}. Focus on grants with deadlines in the next 90 days or rolling applications.`;
  outputFolder = 'Maryland_Grants';
  outputPrefix = grantName ? grantName.replace('.txt','') : 'Grant_Intel_' + new Date().toISOString().slice(0,10);

} else {
  systemMessage = `You are Scout, BD Research Agent for KAI-Netics (${entities.FP?.name}).\nFounder: ${founder.name} — ${(founder.credentials||[]).join(', ')}\nBackground: ${founder.background}\nSeven verticals:\n${verticalList}\nTarget geography: Baltimore City, Anne Arundel, Howard, Baltimore County, PG County, Montgomery County, DC Metro, Northern Virginia.\nTarget customers: 24 MD county DPW offices, BGE/PEPCO/Delmarva, Crown Castle/American Tower, MDSHA (2500+ bridges), DC DDOT (245 bridges), Amazon/Home Depot/Target warehouses, municipal fire/police DFR.\nNAICS registered: ${(naics.registered||[]).map(n=>n.code+' '+n.description).join(', ')}\nCompliance hooks: FHWA 23 CFR 650, PHMSA 49 CFR 192, OMB M-26-02 deadline May 20 2026, NDAA fleet cert, NERC FAC-001/003.\n\nFor each BD target provide:\n1. TARGET ORG and exact decision maker title\n2. PROCUREMENT PORTAL — exact URL\n3. CONTRACT VEHICLE — how they buy this service\n4. FIT SCORE 0-100% with rationale\n5. CAPABILITY STATEMENT — 2 tight paragraphs Kevin can send today\n6. CERTIFICATIONS NEEDED — list gaps\n7. NEXT ACTION — single specific action with URL or name\n8. FOLLOW-UP SEQUENCE — 3-touch outreach plan with timing\n\nBe specific. Name real titles, portals, RFP numbers where known. Today is ${new Date().toLocaleDateString('en-US', {timeZone: 'America/New_York'})}.`;

  userMessage = `Research this BD target for immediate outreach:\n\n${query}\n\nProvide all 8 sections. Prioritize speed to first contact — Kevin can act on this today.`;
  outputFolder = 'Aidan_Outputs/Scout';
  outputPrefix = 'Scout_BD_' + new Date().toISOString().slice(0,10).replace(/-/g,'');
}

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});

const options = {
  hostname: 'api.anthropic.com',
  port: 443,
  path: '/v1/messages',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'x-api-key': 'REPLACE_WITH_KEY',
    'anthropic-version': '2023-06-01',
    'Content-Length': Buffer.byteLength(requestBody)
  }
};

const result = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ status: res.statusCode, body: d }));
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let aiOutput = '';
try {
  aiOutput = JSON.parse(result.body).content?.[0]?.text || 'No response.';
} catch(e) {
  aiOutput = result.body.substring(0, 500);
}

const dateStr = new Date().toISOString().replace(/[:.]/g,'-');
const filename = mode === 'grant' ? `${outputPrefix}.txt` : `${outputPrefix}_${dateStr}.txt`;
const folderPath = `/data/${outputFolder}`;
fs.mkdirSync(folderPath, { recursive: true });
fs.writeFileSync(`${folderPath}/${filename}`, `SCOUT v3 — KAI-NETICS\nMode: ${mode.toUpperCase()}\nQuery: ${query}\nGenerated: ${timestamp}\nScheduled: ${isScheduled}\n\n${aiOutput}\n`, 'utf8');

const fitMatch = aiOutput.match(/(?:FIT SCORE|EAF FIT SCORE)[:\s*\*]*\s*\*?\*?(\d+)/i);
const fitScore = fitMatch ? fitMatch[1] + '%' : 'See report';
const actionMatch = aiOutput.match(/RECOMMENDED ACTION[:\s*\*]*\s*\*?\*?([^\n]+)/i);
const action = actionMatch ? actionMatch[1].trim().replace(/\*/g,'') : 'Review report';
const nextMatch = aiOutput.match(/NEXT (?:STEP|ACTION)[:\s*\*]*\s*\*?\*?([^\n]+)/i);
const nextStep = nextMatch ? nextMatch[1].trim().replace(/\*/g,'').substring(0,80) : 'See report';

const modeLabel = mode === 'grant' ? 'GRANT INTEL' : 'BD REPORT';
const summary = `SCOUT ${modeLabel} COMPLETE\nMode: ${mode.toUpperCase()}\nQuery: ${query.substring(0,60)}\nFit: ${fitScore} | Action: ${action}\nNext: ${nextStep}\nSaved: /data/${outputFolder}/${filename}`;

return [{ json: { aiOutput, summary, savedTo: `${folderPath}/${filename}`, query, fitScore, action, mode, filename, outputFolder, isScheduled, timestamp } }];

const http = require('http');
const { summary = 'Scout complete.', fitScore, query, mode, isScheduled } = $input.first().json;

const msgText = isScheduled
  ? `Bot reply: 🔍 SCOUT MORNING SCAN\n\n${summary}`
  : `Bot reply: SCOUT ${mode?.toUpperCase() === 'GRANT' ? 'GRANT INTEL' : 'BD REPORT'} COMPLETE\n\n${summary}`;

const msgBody = JSON.stringify({
  number: '14432576836@s.whatsapp.net',
  textMessage: { text: msgText }
});

const opts = {
  hostname: 'host.docker.internal',
  port: 8081,
  path: '/message/sendText/Aidan',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'apikey': 'Kevin2026',
    'Content-Length': Buffer.byteLength(msgBody)
  }
};

await new Promise(r => {
  const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); });
  req.on('error',r);
  req.write(msgBody);
  req.end();
});

const cbBody = JSON.stringify({
  agent: 'Scout',
  summary,
  fitScore,
  query,
  mode,
  isScheduled,
  timestamp: new Date().toISOString()
});

const cbOpts = {
  hostname: 'host.docker.internal',
  port: 5678,
  path: '/webhook/aidan-callback',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(cbBody)
  }
};

const cbReq = http.request(cbOpts, res => { res.on('data',()=>{}); res.on('end',()=>{}); });
cbReq.on('error',()=>{});
cbReq.write(cbBody);
cbReq.end();

return [{ json: { success: true, agent: 'Scout', summary, mode } }];
